+    if (self == null) return 0;
+    const cdata: *ctypes.CDataObject = @ptrCast(@alignCast(self.?));
+
+    if (cdata.b_objects) |obj| {
+        if (visit) |v| {
+            const result = v(obj, arg);
+            if (result != 0) return result;
+        }
